sql:
SELECT COUNT(*)
FROM comments
WHERE user_id IN (
  SELECT DISTINCT user_id
  FROM comment_flags
);

SELECT COUNT(*)
FROM comments
WHERE user_id NOT IN (
  SELECT user_id FROM user_bans
);

SELECT COUNT(*) AS num_insults
FROM comment_insults
WHERE is_insult = 1;

SELECT DISTINCT c.user_id
FROM comments c
WHERE c.comment_id IN (
  SELECT cl.comment_id
  FROM comment_likes cl
);

SELECT comment_id
FROM moderator_actions
WHERE action_type = 'ban';

SELECT AVG(total_likes)
FROM (
  SELECT COUNT(*) AS total_likes
  FROM comment_likes
  GROUP BY comment_id
) AS likes_per_comment;

SELECT reply_id 
FROM comment_replies 
WHERE is_anonymous = 1;

SELECT COUNT(ci.comment_id) 
FROM comment_insults ci
WHERE ci.is_insult = 1;

SELECT COUNT(*) AS suspended_comments
FROM moderator_actions
WHERE action_type = 'suspend';

external_knowledge:
- 'statements made' refers to the text of the comments;
- 'reactions they received' refers to the counts of reports, insults, and likes;
- 'complaints' refer to comment reports;
- 'remarks deemed offensive' correspond to insults classified for comments;
- 'positive feedback' refers to likes on comments.

